1	export interface QuoteInput {
2	  items: { type: string }[];
3	}
4	
5	const PROCESSING_FEE = 5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	};
11	
12	export function quote(input: QuoteInput): number {
13	  const basePremiums = input.items.reduce(
14	    (sum, item) => sum + BASE_PREMIUMS[item.type],
15	    0,
16	  );
17	  return basePremiums + PROCESSING_FEE;
18	}
