5	  describe("quote — base premiums and fee", () => {
6	    it("returns 5 G for an empty item list (processing fee only)", () => {
7	      expect(quote({ items: [] })).toBe(5);
8	    });
9	    it("returns 105 G for a single plain sword (100 base + 5 fee)", () => {
10	      expect(quote({ items: [{ type: "sword" }] })).toBe(105);
11	    });
12	    it("returns 65 G for a single plain amulet (60 base + 5 fee)", () => {
13	      expect(quote({ items: [{ type: "amulet" }] })).toBe(65);
14	    });
15	    it.todo("returns 85 G for a single plain staff (80 base + 5 fee)");
16	    it.todo("returns 45 G for a single plain potion (40 base + 5 fee)");
17	    it.todo("returns 30 G for a single rune (25 base + 5 fee)");
18	    it.todo("returns 30 G for a single moonstone (25 base + 5 fee)");
19	  });
20	
21	  describe("quote — component building blocks", () => {
22	    it.todo("returns 55 G for 2 runes (50 base + 5 fee)");
23	    it.todo("returns 65 G for 3 runes (60 base block + 5 fee)");
24	    it.todo("returns 105 G for 4 runes (100 base, no block + 5 fee)");
25	    it.todo("returns 180 G for 7 runes (175 base + 5 fee)");
26	    it.todo("returns 80 G for 2 runes + 1 moonstone (75 base, no block: different types + 5 fee)");
27	    it.todo("returns 125 G for 3 runes + 3 moonstones (120 base, two separate blocks + 5 fee)");
28	  });
29	
30	  describe("quote — item-specific modifiers", () => {
31	    it.todo("adds 50% curse surcharge to a cursed sword's base premium");
32	    it.todo("adds 30% high-enchantment surcharge to a sword with enchantment exactly 5");
33	    it.todo("does not add high-enchantment surcharge to a sword with enchantment 4");
34	    it.todo("applies both curse and high-enchantment surcharges to a cursed sword with enchantment 5");
35	  });
36	
37	  describe("quote — policy-wide modifiers", () => {
38	    it.todo("applies 20% loyalty discount for a customer with exactly 2 years with MHPCO");
39	    it.todo("does not apply loyalty discount for a customer with fewer than 2 years");
40	    it.todo("applies 10% first-insurance surcharge to each item in a quote regardless of history");
41	    it.todo("applies 15% follow-up discount on the customer's second quote in a scenario");
42	  });
43	
44	  describe("quote — modifier scope on multi-item policies", () => {
45	    it.todo("sums item base premiums into the policy base premium for a cursed sword and a plain amulet");
46	    it.todo("applies the curse surcharge to only the cursed item's base premium, not the policy total");
47	  });
48	
49	  describe("quote — rounding", () => {
50	    it.todo("rounds the final premium up to whole G (197.5 → 198)");
51	  });
52	
53	  describe("quote — integration examples", () => {
54	    it.todo("returns 165 G for a newcomer's cursed steel sword at enchantment 3");
55	    it.todo("returns 160 G for a long-standing customer's second-quote cursed steel sword at enchantment 7");
56	  });
57	
58	  describe("claim — standard reimbursement and deductible", () => {
59	    it.todo("pays 400 G for a steel sword enchantment 3 with 500 G damage (full minus 100 deductible)");
60	    it.todo("pays 100 G for a rune with 200 G damage (full minus 100 deductible)");
61	    it.todo("applies the 100 G deductible once per damaged item (sword 500 + amulet 300 → 600)");
62	  });
63	
64	  describe("claim — special clauses", () => {
65	    it.todo("reimburses 50% before deductible for a steel sword at enchantment 9 with 1000 G damage (→ 400)");
